import { useCallback, useMemo } from 'react';
import type { SelectOption } from '@linm-soft-org/linm-web-common-components';
import type { CashVoucherKind } from '../components/kt/CashVoucherList';
import {
  CASH_VOUCHER_REGISTRY,
  getCashVoucherLedgerKind,
  type LedgerKind,
} from '../constants/cashVoucherLedgerKind';
import { formatProcessingLevelLabel } from '../utils/processingLevelLabels';
import { useVoucherInitData } from './useVoucherInitData';
import { useVoucherRegistry } from './useVoucherRegistry';

const FORM_NAME: Record<CashVoucherKind, string> = {
  receipt: 'create-cash-receipt',
  payment: 'create-cash-payment',
};

/** List/form — mức xử lý labels theo registry + init-data (`voucher-list-erp.md` §2) */
export function useProcessingLevelLabels(kind: CashVoucherKind) {
  const voucherTypeCode = CASH_VOUCHER_REGISTRY[kind].voucherTypeCode;
  const { ledgerKind: registryLedgerKind } = useVoucherRegistry(voucherTypeCode);
  const ledgerKind: LedgerKind = registryLedgerKind ?? getCashVoucherLedgerKind(kind);
  const { processingLevelOptions } = useVoucherInitData(FORM_NAME[kind]);

  const levelOptions: SelectOption[] = useMemo(
    () => processingLevelOptions,
    [processingLevelOptions],
  );

  const filterOptions = useMemo(
    () => [{ value: '', label: 'Tất cả mức xử lý' }, ...levelOptions],
    [levelOptions],
  );

  const formatLabel = useCallback(
    (code: string | undefined) => formatProcessingLevelLabel(code, ledgerKind, levelOptions),
    [ledgerKind, levelOptions],
  );

  return {
    ledgerKind,
    voucherTypeCode,
    levelOptions,
    filterOptions,
    formatLabel,
    registryLoaded: registryLedgerKind != null,
  };
}
